## 🛠️ Component Updates

### **ChatController.js - Enhanced**

```javascript
class ChatController {
  async sendMessage(text, mode, selectedSection) {
    // Regular conversation
    const response = await this.getAIResponse(text, mode, selectedSection);

    // Check if AI is proposing a change
    const isProposal = this.detectProposal(response);

    if (isProposal) {
      // Return message with suggestion payload
      return {
        role: 'assistant',
        content: response.explanation,
        type: 'suggestion',
        payload: {
          targetSection: selectedSection.id,
          currentContent: this.getCurrentContent(selectedSection),
          proposedContent: response.proposedContent,
          changeType: response.changeType
        }
      };
    } else {
      // Regular chat message
      return {
        role: 'assistant',
        content: response,
        type: 'conversation'
      };
    }
  }

  // New method: Apply suggested changes
  async commitChange(suggestionPayload) {
    const { targetSection, proposedContent } = suggestionPayload;

    // Update the actual promptData
    AppStateManager.updateSection(targetSection, proposedContent);

    // Add commit message to chat
    AppStateManager.addChatMessage({
      role: 'system',
      content: `✅ Updated section: ${targetSection}`,
      type: 'commit',
      timestamp: Date.now()
    });

    // Update memory - user accepted this type of change
    MemoryStore.recordAcceptedChange(suggestionPayload);
  }

  detectProposal(response) {
    // Check if AI response includes structured change
    return response.includes('proposedContent') || 
           response.changeType !== undefined;
  }
}
```

