### **AppStateManager.js - New Methods**

```javascript
class AppStateManager {
  // Update specific section content
  updateSection(sectionId, newContent, subsectionId = null) {
    const section = this.state.promptData.sections.find(s => s.id === sectionId);

    if (subsectionId) {
      // Update subsection
      const subsection = section.subsections.find(sub => sub.id === subsectionId);
      subsection.content = newContent;
    } else {
      // Update section
      section.content = newContent;
    }

    this.notifyListeners();
    this.saveToMemory(); // Auto-save changes
  }

  // Mark message as rejected
  markMessageRejected(messageId) {
    const message = this.state.chatHistory.find(m => m.id === messageId);
    message.status = 'rejected';
    this.notifyListeners();
  }

  // Get change history for a section
  getSectionHistory(sectionId) {
    return this.state.chatHistory
      .filter(msg => msg.type === 'commit' && msg.payload.targetSection === sectionId)
      .sort((a, b) => b.timestamp - a.timestamp);
  }
}
```

